            {title}
          </h2>
          <div className="h-px bg-zinc-100 w-full"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {students.map((student) => (
            <div key={student.id} className="group relative h-full">
               {editingId === student.id ? renderEditForm(false) : (
                 <div className="p-6 rounded-2xl bg-white border border-zinc-100 hover:border-zinc-300 hover:shadow-lg transition-all duration-300 h-full flex flex-col">
