import React, { useState } from 'react';
import { useLab } from '../context/LabContext';
import { ArrowUpRight, Plus, Trash2, Pencil, Save, X, Upload } from 'lucide-react';
import { ResearchArea } from '../types';

export const Research: React.FC = () => {
  const { researchAreas, isAdmin, addResearchArea, updateResearchArea, deleteResearchArea } = useLab();
  const [isAdding, setIsAdding] = useState(false);
  const [newArea, setNewArea] = useState({ title: '', description: '', link: '', imageUrl: '' });

  // Edit State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<ResearchArea>>({});

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        if (isEdit) {
          setEditForm(prev => ({ ...prev, imageUrl: result }));
        } else {
          setNewArea(prev => ({ ...prev, imageUrl: result }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    addResearchArea({
      id: Date.now().toString(),
      title: newArea.title,
      description: newArea.description,
      imageUrl: newArea.imageUrl || `https://picsum.photos/600/400?random=${Date.now()}`,
      link: newArea.link || '#'
    });
    setNewArea({ title: '', description: '', link: '', imageUrl: '' });
    setIsAdding(false);
  };

  const startEditing = (area: ResearchArea) => {
    setEditingId(area.id);
    setEditForm({ ...area });
  };

  const saveEditing = () => {
    if (editingId && editForm.title) {
      updateResearchArea(editingId, editForm);
      setEditingId(null);
    }
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div className="max-w-3xl space-y-4">
          <h1 className="text-4xl font-bold text-zinc-900">Research</h1>
          <p className="text-lg text-zinc-500">
            Our work spans multiple disciplines, aiming to solve fundamental problems in artificial intelligence.
          </p>
        </div>
        {isAdmin && !isAdding && (
          <button onClick={() => setIsAdding(true)} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-xl">
            <Plus size={18} /> Add Area
          </button>
        )}
      </div>

      {isAdding && (
         <form onSubmit={handleAdd} className="p-6 bg-zinc-50 border rounded-2xl space-y-4">
            <input required placeholder="Title" className="w-full p-3 border rounded-xl" value={newArea.title} onChange={e => setNewArea({...newArea, title: e.target.value})} />
            <textarea required placeholder="Description" className="w-full p-3 border rounded-xl" value={newArea.description} onChange={e => setNewArea({...newArea, description: e.target.value})} />

            <div className="grid md:grid-cols-2 gap-4">
               <div className="flex gap-2">
                 <input placeholder="Image URL (https://...)" className="flex-1 p-3 border rounded-xl" value={newArea.imageUrl || ''} onChange={e => setNewArea({...newArea, imageUrl: e.target.value})} />
                 <label className="flex items-center justify-center px-4 bg-zinc-100 border border-zinc-200 rounded-xl cursor-pointer hover:bg-zinc-200">
                    <Upload size={20} className="text-zinc-500" />
                    <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, false)} />
                 </label>
               </div>
               <input placeholder="Project Link (Optional)" className="w-full p-3 border rounded-xl" value={newArea.link} onChange={e => setNewArea({...newArea, link: e.target.value})} />
            </div>

            <div className="flex gap-3">
              <button type="submit" className="bg-zinc-900 text-white px-4 py-2 rounded-lg">Save</button>
              <button type="button" onClick={() => setIsAdding(false)} className="bg-white border px-4 py-2 rounded-lg">Cancel</button>
            </div>
         </form>
      )}

      <div className="space-y-20">
        {researchAreas.map((area, index) => (
          <div key={area.id} className="relative group">
            {editingId === area.id ? (
              // EDIT MODE
              <div className="p-6 bg-zinc-50 border-2 border-blue-500 rounded-2xl space-y-4">
                <div className="flex justify-between items-center">
                   <h4 className="font-bold text-blue-600">Editing Research Area</h4>
                   <button onClick={() => setEditingId(null)} className="text-zinc-400 hover:text-zinc-600"><X size={20}/></button>
                </div>
                <input className="w-full p-3 border rounded-xl" placeholder="Title" value={editForm.title || ''} onChange={e => setEditForm({...editForm, title: e.target.value})} />
                <textarea className="w-full p-3 border rounded-xl h-32" placeholder="Description" value={editForm.description || ''} onChange={e => setEditForm({...editForm, description: e.target.value})} />

                <div className="space-y-2">
                   <div className="flex gap-2">
                     <input className="flex-1 p-3 border rounded-xl" placeholder="Image URL" value={editForm.imageUrl || ''} onChange={e => setEditForm({...editForm, imageUrl: e.target.value})} />
                     <label className="flex items-center justify-center px-4 bg-white border border-zinc-200 rounded-xl cursor-pointer hover:bg-zinc-50">
                        <Upload size={20} className="text-zinc-500" />
                        <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, true)} />
                     </label>
                   </div>
                   <input className="w-full p-3 border rounded-xl" placeholder="Project URL (e.g. https://...)" value={editForm.link || ''} onChange={e => setEditForm({...editForm, link: e.target.value})} />
                </div>

                <button onClick={saveEditing} className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700">
                  <Save size={16} /> Save Changes
                </button>
              </div>
            ) : (
              // VIEW MODE
              <div className={`flex flex-col md:flex-row gap-8 items-center ${index % 2 === 1 ? 'md:flex-row-reverse' : ''}`}>
                 {isAdmin && (
                    <div className="absolute top-0 right-0 z-20 flex gap-2 bg-white/80 backdrop-blur-sm p-2 rounded-xl shadow-sm">
                      <button 
                        onClick={(e) => { e.stopPropagation(); startEditing(area); }}
                        className="p-2 bg-blue-100 text-blue-600 rounded-lg hover:bg-blue-200"
                      >
                        <Pencil size={16} />
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); if(window.confirm('Delete area?')) deleteResearchArea(area.id); }}
                        className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  )}
                <div className="w-full md:w-1/2 aspect-video rounded-2xl overflow-hidden shadow-sm">
                  <img 
                    src={area.imageUrl} 
                    alt={area.title} 
                    className="w-full h-full object-cover transition-transform duration-700 hover:scale-105"
                  />
                </div>

                <div className="w-full md:w-1/2 space-y-4">
                  <h3 className="text-2xl font-bold text-zinc-900">{area.title}</h3>
                  <p className="text-zinc-600 leading-relaxed text-lg">
                    {area.description}
                  </p>
                  <a 
                    href={area.link} 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    className={`flex items-center gap-2 text-blue-600 font-medium hover:underline ${(!area.link || area.link === '#') ? 'opacity-50 cursor-not-allowed' : ''}`}
                    onClick={(e) => (!area.link || area.link === '#') && e.preventDefault()}
                  >
                    Read more about this project <ArrowUpRight size={18} />
                  </a>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useLab } from '../context/LabContext';
import { FileText, Plus, Trash2, Pencil, Save, X, ExternalLink } from 'lucide-react';
import { Publication } from '../types';

export const Publications: React.FC = () => {
  const { publications, isAdmin, addPublication, updatePublication, deletePublication } = useLab();
  const [filterYear, setFilterYear] = useState<number | 'All'>('All');

  // Adding State
  const [isAdding, setIsAdding] = useState(false);
  const [newPub, setNewPub] = useState({ title: '', venue: '', year: new Date().getFullYear(), authors: '', doi: '' });

  // Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Publication> & { authorsStr?: string }>({});

  const years = Array.from(new Set(publications.map(p => p.year))).sort((a, b) => b - a);
  const filteredPublications = filterYear === 'All' 
    ? publications 
    : publications.filter(p => p.year === filterYear);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    addPublication({
      id: Date.now().toString(),
      title: newPub.title,
      venue: newPub.venue,
      year: Number(newPub.year),
      authors: newPub.authors.split(',').map(s => s.trim()),
      doi: newPub.doi,
      link: '#',
      tags: []
    });
    setNewPub({ title: '', venue: '', year: new Date().getFullYear(), authors: '', doi: '' });
    setIsAdding(false);
  };

  const startEditing = (pub: Publication) => {
    setEditingId(pub.id);
    setEditForm({ ...pub, authorsStr: pub.authors.join(', ') });
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditForm({});
  };

  const saveEditing = () => {
    if (editingId && editForm.title && editForm.authorsStr) {
      updatePublication(editingId, {
        ...editForm,
        authors: editForm.authorsStr.split(',').map(s => s.trim())
      });
      setEditingId(null);
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-zinc-100 pb-8">
        <div className="space-y-4">
          <h1 className="text-4xl font-bold text-zinc-900">Publications</h1>
          <p className="text-lg text-zinc-500">
            Selected papers from top-tier conferences and journals.
          </p>
        </div>

        <div className="flex items-center gap-4">
          {isAdmin && !isAdding && (
            <button onClick={() => setIsAdding(true)} className="flex items-center gap-2 bg-blue-600 text-white px-3 py-2 rounded-lg text-sm whitespace-nowrap">
              <Plus size={16} /> Add
            </button>
          )}
          {/* Year Filter */}
          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
            <button
              onClick={() => setFilterYear('All')}
              className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                filterYear === 'All' 
                  ? 'bg-zinc-900 text-white' 
                  : 'bg-zinc-100 text-zinc-600 hover:bg-zinc-200'
              }`}
            >
              All Years
            </button>
            {years.map(year => (
              <button
                key={year}
                onClick={() => setFilterYear(year)}
                className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                  filterYear === year
                    ? 'bg-zinc-900 text-white' 
                    : 'bg-zinc-100 text-zinc-600 hover:bg-zinc-200'
                }`}
              >
                {year}
              </button>
            ))}
          </div>
        </div>
      </div>

      {isAdding && (
        <form onSubmit={handleAdd} className="p-6 bg-zinc-50 border rounded-2xl space-y-4">
           <h3 className="font-bold text-lg">Add New Publication</h3>
           <div className="grid md:grid-cols-2 gap-4">
             <input required placeholder="Title" className="col-span-2 p-3 border rounded-xl" value={newPub.title} onChange={e => setNewPub({...newPub, title: e.target.value})} />
             <input required placeholder="Venue (e.g. CVPR)" className="p-3 border rounded-xl" value={newPub.venue} onChange={e => setNewPub({...newPub, venue: e.target.value})} />
             <input required type="number" placeholder="Year" className="p-3 border rounded-xl" value={newPub.year} onChange={e => setNewPub({...newPub, year: Number(e.target.value)})} />
             <input required placeholder="Authors (comma separated)" className="col-span-2 p-3 border rounded-xl" value={newPub.authors} onChange={e => setNewPub({...newPub, authors: e.target.value})} />
             <input placeholder="DOI Link (e.g., https://doi.org/...)" className="col-span-2 p-3 border rounded-xl" value={newPub.doi} onChange={e => setNewPub({...newPub, doi: e.target.value})} />
           </div>
           <div className="flex gap-3">
              <button type="submit" className="bg-zinc-900 text-white px-4 py-2 rounded-lg">Save</button>
              <button type="button" onClick={() => setIsAdding(false)} className="bg-white border px-4 py-2 rounded-lg">Cancel</button>
            </div>
        </form>
      )}

      <div className="space-y-4">
        {filteredPublications.map((pub) => (
          <div key={pub.id} className="group relative">
            {editingId === pub.id ? (
              // EDIT MODE
              <div className="p-6 rounded-2xl bg-zinc-50 border-2 border-blue-500 space-y-4">
                 <div className="flex justify-between items-center">
                    <h4 className="font-bold text-blue-600">Editing Publication</h4>
                    <button onClick={cancelEditing} className="text-zinc-400 hover:text-zinc-600"><X size={20}/></button>
                 </div>
                 <div className="space-y-3">
                   <input className="w-full p-2 border rounded-lg" placeholder="Title" value={editForm.title || ''} onChange={e => setEditForm({...editForm, title: e.target.value})} />
                   <div className="grid grid-cols-2 gap-3">
                     <input className="p-2 border rounded-lg" placeholder="Venue" value={editForm.venue || ''} onChange={e => setEditForm({...editForm, venue: e.target.value})} />
                     <input type="number" className="p-2 border rounded-lg" placeholder="Year" value={editForm.year || ''} onChange={e => setEditForm({...editForm, year: Number(e.target.value)})} />
                   </div>
                   <input className="w-full p-2 border rounded-lg" placeholder="Authors (comma separated)" value={editForm.authorsStr || ''} onChange={e => setEditForm({...editForm, authorsStr: e.target.value})} />
                   <input className="w-full p-2 border rounded-lg" placeholder="DOI Link (https://...)" value={editForm.doi || ''} onChange={e => setEditForm({...editForm, doi: e.target.value})} />
                 </div>
                 <div className="flex gap-2">
                    <button onClick={saveEditing} className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700">
                      <Save size={16} /> Save Changes
                    </button>
                 </div>
              </div>
            ) : (
              // VIEW MODE
              <div className="p-6 rounded-2xl bg-white border border-zinc-100 hover:border-blue-200 hover:shadow-md transition-all duration-200">
                 {isAdmin && (
                    <div className="absolute top-4 right-4 z-20 flex gap-2">
                      <button 
                        onClick={(e) => { e.stopPropagation(); startEditing(pub); }}
                        className="p-2 bg-blue-100 text-blue-600 rounded-lg hover:bg-blue-200"
                      >
                        <Pencil size={16} />
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); if(window.confirm('Delete publication?')) deletePublication(pub.id); }}
                        className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  )}
                <div className="flex flex-col md:flex-row justify-between gap-4">
                  <div className="space-y-2 pr-20">
                    <div className="flex items-center gap-3">
                       <span className="font-mono text-sm font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded">
                        {pub.venue} {pub.year}
                      </span>
                      {pub.tags?.map(tag => (
                        <span key={tag} className="text-xs text-zinc-400 border border-zinc-100 px-2 py-0.5 rounded">
                          {tag}
                        </span>
                      ))}
                    </div>

                    <h3 className="text-xl font-bold text-zinc-900 leading-tight group-hover:text-blue-600 transition-colors">
                      {pub.title}
                    </h3>

                    <p className="text-zinc-600">
                      {pub.authors.map((author, i) => (
                        <span key={i} className={author.includes("S. You") ? "font-semibold text-zinc-900" : ""}>
                          {author}{i < pub.authors.length - 1 ? ", " : ""}
                        </span>
                      ))}
                    </p>
                  </div>

                  <div className="flex items-start pt-2 flex-shrink-0">
                    {pub.doi && (
                      <a 
                        href={pub.doi} 
                        target="_blank"
                        rel="noreferrer"
                        className="flex items-center gap-2 px-4 py-2 rounded-lg bg-zinc-50 text-zinc-600 text-sm font-medium hover:bg-blue-600 hover:text-white transition-colors"
                      >
                        <ExternalLink size={16} />
                        <span>DOI / PDF</span>
                      </a>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        ))}

        {filteredPublications.length === 0 && (
            <div className="text-center py-20 text-zinc-400">
                No publications found for this year.
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LAB_NAME } from '../constants';
import { useLab } from '../context/LabContext';
import { ArrowRight, Sparkles, Plus, Trash2, ExternalLink, Pencil, Save, X, Image as ImageIcon, Upload } from 'lucide-react';
import { Link } from 'react-router-dom';
import { NewsItem } from '../types';

export const Home: React.FC = () => {
  const { news, isAdmin, addNews, updateNews, deleteNews, homeImage, updateHomeImage } = useLab();

  // News Adding State
  const [isAdding, setIsAdding] = useState(false);
  const [newPost, setNewPost] = useState({ 
    title: '', 
    content: '', 
    date: new Date().toISOString().split('T')[0] 
  });

  // News Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<NewsItem>>({});

  // Home Image Editing State
  const [isEditingImage, setIsEditingImage] = useState(false);
  const [tempImageUrl, setTempImageUrl] = useState('');

  // --- Image Handlers ---
  const startEditingImage = () => {
    setTempImageUrl(homeImage);
    setIsEditingImage(true);
  };

  const saveImage = () => {
    if (tempImageUrl.trim()) {
      updateHomeImage(tempImageUrl.trim());
      setIsEditingImage(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempImageUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- News Handlers ---
  const handleAddNews = (e: React.FormEvent) => {
    e.preventDefault();
    addNews({
      id: Date.now().toString(),
      date: newPost.date.replace(/-/g, '.'),
      title: newPost.title,
      content: newPost.content
    });
    setNewPost({ title: '', content: '', date: new Date().toISOString().split('T')[0] });
    setIsAdding(false);
  };

  const startEditing = (item: NewsItem) => {
    setEditingId(item.id);
    // Convert YYYY.MM.DD (display) -> YYYY-MM-DD (input)
    setEditForm({ 
      ...item,
      date: item.date.replace(/\./g, '-')
    });
  };

  const saveEditing = () => {
    if (editingId && editForm.title && editForm.date) {
      updateNews(editingId, {
        ...editForm,
        // Convert YYYY-MM-DD (input) -> YYYY.MM.DD (display)
        date: editForm.date.replace(/-/g, '.')
      });
      setEditingId(null);
    }
  };

  return (
    <div className="space-y-16 animate-in fade-in duration-500">
      {/* Hero Section */}
      <section className="space-y-6">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-100 text-zinc-600 text-xs font-medium uppercase tracking-wider">
          <Sparkles size={12} className="text-blue-600" />
          Laboratory for Human Behavior in Crisis
        </div>
        <h1 className="text-4xl md:text-6xl font-extrabold tracking-tight text-zinc-900 leading-[1.1]">
          Understanding <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">human behavior</span> in times of crisis.
        </h1>
        <p className="text-lg md:text-xl text-zinc-500 max-w-2xl leading-relaxed">
          Welcome to {LAB_NAME} at Chungbuk National University. We research trauma, crisis intervention, and resilience to help individuals and society recover and grow.
        </p>
        <div className="flex flex-wrap gap-4 pt-4">
          <Link 
            to="/research" 
            className="inline-flex items-center gap-2 bg-zinc-900 text-white px-6 py-3 rounded-xl font-medium hover:bg-zinc-800 transition-all hover:scale-[1.02] active:scale-95"
          >
            Our Research <ArrowRight size={18} />
          </Link>
          <a 
            href="https://psychology.chungbuk.ac.kr/" 
            target="_blank"
            rel="noreferrer"
            className="inline-flex items-center gap-2 bg-white border border-zinc-200 text-zinc-700 px-6 py-3 rounded-xl font-medium hover:bg-zinc-50 transition-all hover:border-zinc-300"
          >
            Dept. Website <ExternalLink size={16} />
          </a>
        </div>
      </section>

      {/* Image Banner */}
      <div className="relative w-full h-64 md:h-96 rounded-2xl overflow-hidden shadow-sm group">
        {isEditingImage ? (
          <div className="absolute inset-0 bg-zinc-50 z-20 flex flex-col items-center justify-center p-6 gap-4">
             <h3 className="font-bold text-lg text-zinc-900">Update Banner Image</h3>

             <div className="w-full max-w-md space-y-3">
               <div className="flex gap-2">
                 <input 
                    className="flex-1 p-3 border rounded-xl shadow-sm"
                    placeholder="Enter Image URL..."
                    value={tempImageUrl}
                    onChange={(e) => setTempImageUrl(e.target.value)}
                    autoFocus
                 />
                 <button onClick={saveImage} className="bg-blue-600 text-white px-4 rounded-xl hover:bg-blue-700">Save</button>
                 <button onClick={() => setIsEditingImage(false)} className="bg-white border text-zinc-700 px-4 rounded-xl hover:bg-zinc-50">Cancel</button>
               </div>

               <div className="relative">
                  <div className="absolute inset-0 flex items-center">
                    <span className="w-full border-t border-zinc-300" />
                  </div>
                  <div className="relative flex justify-center text-xs uppercase">
                    <span className="bg-zinc-50 px-2 text-zinc-500">Or upload file</span>
                  </div>
               </div>

               <div className="flex items-center justify-center w-full">
                  <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-zinc-300 border-dashed rounded-xl cursor-pointer bg-zinc-50 hover:bg-zinc-100 transition-colors">
                      <div className="flex flex-col items-center justify-center pt-5 pb-6">
                          <Upload className="w-8 h-8 text-zinc-400 mb-2" />
                          <p className="text-sm text-zinc-500">Click to upload image</p>
                      </div>
                      <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                  </label>
               </div>
             </div>
          </div>
        ) : (
          <>
            <img 
              src={homeImage} 
              alt="Lab environment" 
              className="w-full h-full object-cover hover:scale-105 transition-transform duration-700"
            />
            {isAdmin && (
              <button 
                onClick={startEditingImage}
                className="absolute top-4 right-4 z-20 bg-white/90 backdrop-blur text-zinc-800 px-4 py-2 rounded-lg text-sm font-medium shadow-sm hover:bg-white flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-200"
              >
                <ImageIcon size={16} /> Edit Image
              </button>
            )}
          </>
        )}
      </div>

      {/* News Section */}
      <section>
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-2xl font-bold text-zinc-900">Lab News</h2>
          {isAdmin && !isAdding && (
            <button 
              onClick={() => setIsAdding(true)}
              className="flex items-center gap-2 text-sm bg-blue-600 text-white px-3 py-1.5 rounded-lg hover:bg-blue-700 transition-colors"
            >
              <Plus size={16} /> Add News
            </button>
          )}
          {!isAdmin && <span className="text-sm text-zinc-400">Updates & Announcements</span>}
        </div>

        {isAdding && (
          <form onSubmit={handleAddNews} className="mb-8 p-6 bg-zinc-50 border border-zinc-200 rounded-2xl space-y-4">
            <h3 className="font-bold text-lg">Add New Post</h3>
            <div className="flex gap-4">
              <input
                type="date"
                required
                className="p-3 border rounded-xl"
                value={newPost.date}
                onChange={e => setNewPost({...newPost, date: e.target.value})}
              />
              <input
                required
                placeholder="Title"
                className="flex-1 p-3 border rounded-xl"
                value={newPost.title}
                onChange={e => setNewPost({...newPost, title: e.target.value})}
              />
            </div>
            <textarea
              required
              placeholder="Content"
              className="w-full p-3 border rounded-xl h-24"
              value={newPost.content}
              onChange={e => setNewPost({...newPost, content: e.target.value})}
            />
            <div className="flex gap-3">
              <button type="submit" className="bg-zinc-900 text-white px-4 py-2 rounded-lg">Save</button>
              <button type="button" onClick={() => setIsAdding(false)} className="bg-white border px-4 py-2 rounded-lg">Cancel</button>
            </div>
          </form>
        )}

        <div className="grid gap-6">
          {news.map((item) => (
            <div key={item.id} className="group relative">
               {editingId === item.id ? (
                 // Edit Mode
                 <div className="p-6 rounded-2xl bg-zinc-50 border-2 border-blue-500 space-y-4">
                    <div className="flex justify-between items-center">
                      <h4 className="font-bold text-blue-600">Editing Post</h4>
                      <button onClick={() => setEditingId(null)} className="text-zinc-400 hover:text-zinc-600"><X size={20}/></button>
                    </div>
                    <div className="flex flex-col md:flex-row gap-4">
                      <input 
                        type="date"
                        className="p-3 border rounded-xl"
                        value={editForm.date || ''}
                        onChange={e => setEditForm({...editForm, date: e.target.value})}
                      />
                      <input 
                        className="flex-1 p-3 border rounded-xl" 
                        value={editForm.title || ''} 
                        onChange={e => setEditForm({...editForm, title: e.target.value})} 
                      />
                    </div>
                    <textarea 
                      className="w-full p-3 border rounded-xl h-24" 
                      value={editForm.content || ''} 
                      onChange={e => setEditForm({...editForm, content: e.target.value})} 
                    />
                    <button onClick={saveEditing} className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700">
                      <Save size={16} /> Save Changes
                    </button>
                 </div>
               ) : (
                 // View Mode
                  <div className="flex flex-col md:flex-row gap-4 md:gap-8 p-6 rounded-2xl bg-zinc-50 border border-zinc-100 hover:border-zinc-200 transition-colors">
                    {isAdmin && (
                      <div className="absolute top-4 right-4 z-20 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                        <button 
                          onClick={(e) => { e.stopPropagation(); startEditing(item); }}
                          className="p-2 bg-white text-blue-600 rounded-lg shadow-sm hover:bg-blue-50 border border-zinc-100"
                        >
                          <Pencil size={16} />
                        </button>
                        <button 
                          onClick={(e) => { e.stopPropagation(); if(window.confirm('Delete this post?')) deleteNews(item.id); }}
                          className="p-2 bg-white text-red-500 rounded-lg shadow-sm hover:bg-red-50 border border-zinc-100"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    )}
                    <div className="md:w-32 flex-shrink-0">
                      <span className="inline-block px-3 py-1 bg-white rounded-md text-xs font-semibold text-zinc-500 shadow-sm border border-zinc-100">
                        {item.date}
                      </span>
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-zinc-900 mb-2 group-hover:text-blue-600 transition-colors">
                        {item.title}
                      </h3>
                      <p className="text-zinc-600 leading-relaxed">
                        {item.content}
                      </p>
                    </div>
                  </div>
               )}
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

import React, { useState } from 'react';
import { useLab } from '../context/LabContext';
import { Mail, Plus, Trash2, Pencil, Save, X, PlusCircle, Upload } from 'lucide-react';
import { Member } from '../types';

export const Members: React.FC = () => {
  const { members, isAdmin, addMember, updateMember, deleteMember } = useLab();
  const [isAdding, setIsAdding] = useState(false);

  // State for Editing
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Member>>({});
  const [editInterestInput, setEditInterestInput] = useState('');

  // State for Adding
  const [newMember, setNewMember] = useState<Partial<Member>>({
    role: 'PhD Student',
    researchInterests: [],
    imageUrl: ''
  });
  const [interestInput, setInterestInput] = useState('');

  const professor = members.find(m => m.role === 'Principal Investigator');
  const phdStudents = members.filter(m => m.role === 'PhD Student');
  const masterStudents = members.filter(m => m.role === 'Master Student');
  const alumni = members.filter(m => m.role === 'Alumni');

  // --- Handlers ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        if (isEdit) {
          setEditForm(prev => ({ ...prev, imageUrl: result }));
        } else {
          setNewMember(prev => ({ ...prev, imageUrl: result }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMember.name || !newMember.role) return;

    addMember({
      id: Date.now().toString(),
      name: newMember.name,
      role: newMember.role as any,
      email: newMember.email || '',
      imageUrl: newMember.imageUrl || `https://picsum.photos/200/200?random=${Date.now()}`,
      researchInterests: newMember.researchInterests || [],
    });
    setNewMember({ role: 'PhD Student', researchInterests: [], imageUrl: '' });
    setIsAdding(false);
  };

  const addInterest = () => {
    if (interestInput.trim()) {
      setNewMember(prev => ({
        ...prev,
        researchInterests: [...(prev.researchInterests || []), interestInput.trim()]
      }));
      setInterestInput('');
    }
  };

  // --- EDIT Handlers ---
  const startEditing = (member: Member) => {
    setEditingId(member.id);
    setEditForm({ ...member });
    setEditInterestInput('');
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditForm({});
    setEditInterestInput('');
  };

  const saveEditing = () => {
    if (editingId && editForm.name) {
      updateMember(editingId, editForm);
      setEditingId(null);
    }
  };

  const addEditInterest = () => {
    if (editInterestInput.trim()) {
      setEditForm(prev => ({
        ...prev,
        researchInterests: [...(prev.researchInterests || []), editInterestInput.trim()]
      }));
      setEditInterestInput('');
    }
  };

  const removeEditInterest = (index: number) => {
    setEditForm(prev => ({
      ...prev,
      researchInterests: prev.researchInterests?.filter((_, i) => i !== index)
    }));
  };

  // --- Render Helpers ---
  const renderEditForm = (isProfessor: boolean) => (
    <div className={`bg-zinc-50 border-2 border-blue-500 rounded-2xl p-6 space-y-4 ${isProfessor ? 'w-full' : 'h-full'}`}>
      <div className="flex justify-between items-center mb-2">
        <h4 className="font-bold text-blue-600">Editing Member</h4>
        <button onClick={cancelEditing} className="text-zinc-400 hover:text-zinc-600"><X size={20}/></button>
      </div>

      <div className="space-y-3">
        <div>
          <label className="text-xs font-bold text-zinc-500 uppercase">Name</label>
          <input 
            className="w-full p-2 border rounded-lg" 
            value={editForm.name || ''} 
            onChange={e => setEditForm({...editForm, name: e.target.value})} 
          />
        </div>

        <div>
          <label className="text-xs font-bold text-zinc-500 uppercase">Role</label>
          <select 
            className="w-full p-2 border rounded-lg" 
            value={editForm.role} 
            onChange={e => setEditForm({...editForm, role: e.target.value as any})}
          >
             <option>Principal Investigator</option>
             <option>PhD Student</option>
             <option>Master Student</option>
             <option>Alumni</option>
          </select>
        </div>

        <div>
          <label className="text-xs font-bold text-zinc-500 uppercase">Email</label>
          <input 
            className="w-full p-2 border rounded-lg" 
            value={editForm.email || ''} 
            onChange={e => setEditForm({...editForm, email: e.target.value})} 
          />
        </div>

        <div>
          <label className="text-xs font-bold text-zinc-500 uppercase">Image</label>
          <div className="space-y-2">
             <input 
              className="w-full p-2 border rounded-lg text-sm" 
              placeholder="Image URL (https://...)"
              value={editForm.imageUrl || ''} 
              onChange={e => setEditForm({...editForm, imageUrl: e.target.value})} 
            />
            <div className="flex items-center gap-2">
               <span className="text-xs text-zinc-400">OR</span>
               <label className="cursor-pointer inline-flex items-center gap-2 px-3 py-1.5 bg-white border border-zinc-200 rounded-lg text-xs font-medium hover:bg-zinc-50">
                  <Upload size={14} /> Upload File
                  <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, true)} />
               </label>
            </div>
          </div>
        </div>

        <div>
           <label className="text-xs font-bold text-zinc-500 uppercase">Research Interests</label>
           <div className="flex gap-2 mb-2">
             <input 
               className="flex-1 p-2 border rounded-lg text-sm"
               placeholder="Add interest..."
               value={editInterestInput}
               onChange={e => setEditInterestInput(e.target.value)}
               onKeyDown={e => { if(e.key === 'Enter') { e.preventDefault(); addEditInterest(); }}}
             />
             <button type="button" onClick={addEditInterest} className="p-2 bg-zinc-200 rounded-lg hover:bg-zinc-300">
               <PlusCircle size={16} />
             </button>
           </div>
           <div className="flex flex-wrap gap-1">
             {editForm.researchInterests?.map((interest, idx) => (
               <span key={idx} className="inline-flex items-center gap-1 px-2 py-1 bg-white border rounded text-xs">
                 {interest}
                 <button type="button" onClick={() => removeEditInterest(idx)} className="text-red-400 hover:text-red-600">
                   <X size={12} />
                 </button>
               </span>
             ))}
           </div>
        </div>
      </div>

      <div className="flex gap-2 pt-2">
        <button onClick={saveEditing} className="flex-1 bg-blue-600 text-white py-2 rounded-lg flex items-center justify-center gap-2 hover:bg-blue-700">
          <Save size={16} /> Save Changes
        </button>
      </div>
    </div>
  );

  const renderStudentGrid = (title: string, students: Member[]) => {
    if (students.length === 0) return null;
    return (
